import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../core/utils/app_utils.dart';import '../data/app_repository.dart';class ExpensesScreen extends ConsumerWidget{const ExpensesScreen({super.key});Future<void> add(BuildContext context,WidgetRef ref)async{final f=GlobalKey<FormState>(),c=TextEditingController(text:'Transport'),d=TextEditingController(),a=TextEditingController();final ok=await showDialog<bool>(context:context,builder:(x)=>AlertDialog(title:const Text('Record expense'),content:Form(key:f,child:Column(mainAxisSize:MainAxisSize.min,children:[TextFormField(controller:c,decoration:const InputDecoration(labelText:'Category'),validator:(v)=>Validators.requiredText(v)),const SizedBox(height:10),TextFormField(controller:d,decoration:const InputDecoration(labelText:'Description'),validator:(v)=>Validators.requiredText(v)),const SizedBox(height:10),TextFormField(controller:a,keyboardType:TextInputType.number,decoration:const InputDecoration(labelText:'Amount'),validator:Validators.money)])),actions:[TextButton(onPressed:()=>Navigator.pop(x),child:const Text('Cancel')),FilledButton(onPressed:(){if(f.currentState!.validate())Navigator.pop(x,true);},child:const Text('Save'))]));if(ok==true)await ref.read(repoProvider).addExpense(c.text.trim(),d.text.trim(),double.parse(a.text),'cash');}@override Widget build(BuildContext context,WidgetRef ref){final x=ref.watch(expensesProvider);return Scaffold(appBar:AppBar(title:const Text('Expenses')),body:x.when(loading:()=>const Center(child:CircularProgressIndicator()),error:(e,_)=>Center(child:Text('$e')),data:(v)=>v.isEmpty?const Center(child:Text('No expenses yet')):ListView.builder(padding:const EdgeInsets.all(16),itemCount:v.length,itemBuilder:(_,i)=>Card(child:ListTile(title:Text(v[i].description,style:const TextStyle(fontWeight:FontWeight.w900)),subtitle:Text(v[i].category),trailing:Text(formatGhs(v[i].amount)))))),floatingActionButton:FloatingActionButton.extended(onPressed:()=>add(context,ref),icon:const Icon(Icons.add),label:const Text('Add expense')));}}
